    const INF = Infinity;
    const dist = Array(m).fill().map(() => Array(n).fill().map(() => [INF, INF]));
    const pq = [];
    dist[0][0][1] = 1;
    pq.push([1, 0, 0, 1]);

    while (pq.length > 0) {
        let minIndex = 0;
        for (let i = 1; i < pq.length; i++) {
            if (pq[i][0] < pq[minIndex][0]) {
